import{_ as s}from"./chunks/codex-client-open-project.Bs1XvnsM.js";import{_ as a,o as e,c as t,a2 as o}from"./chunks/framework.DnrXFDHb.js";const d="/images/screenshots/codex-client-first-message.png",g=JSON.parse('{"title":"Codex 配置","description":"","frontmatter":{},"headers":[],"relativePath":"guide/codex.md","filePath":"guide/codex.md","lastUpdated":1782204362000}'),l={name:"guide/codex.md"};function n(h,i,c,p,r,k){return e(),t("div",null,[...i[0]||(i[0]=[o('<h1 id="codex-配置" tabindex="-1">Codex 配置 <a class="header-anchor" href="#codex-配置" aria-label="Permalink to &quot;Codex 配置&quot;">​</a></h1><p>本页用于把已经安装好的 Codex 接入 CCWSPro。新用户请先完成 <a href="/guide/codex-install">Codex 下载安装</a>，再继续本页配置。</p><p>开始前请先准备好：</p><ul><li>已完成 <a href="/guide/codex-install">Codex 下载安装</a>。</li><li>已完成 <a href="/guide/register">注册 / 登录</a> 和 <a href="/guide/recharge">充值 / 续费</a>。</li><li>已获取 CCWSPro 的 <a href="/guide/api-key">请求地址 / API Key</a>。</li><li>命令行方式用户已完成 <a href="/guide/nodejs-git">Node.js 与 Git 环境</a>。</li><li>已安装并配置 <a href="/guide/config-switch">CC Switch 使用教程</a>。</li></ul><div class="tip custom-block"><p class="custom-block-title">推荐</p><p>普通用户推荐使用 <code>Codex 客户端</code> + <code>CC Switch</code>。这样不需要手动编辑配置文件，也更容易在不同 Provider 之间切换。</p></div><h2 id="客户端配置-推荐" tabindex="-1">客户端配置（推荐） <a class="header-anchor" href="#客户端配置-推荐" aria-label="Permalink to &quot;客户端配置（推荐）&quot;">​</a></h2><h3 id="_1-通过-cc-switch-启用-ccwspro" tabindex="-1">1. 通过 CC Switch 启用 CCWSPro <a class="header-anchor" href="#_1-通过-cc-switch-启用-ccwspro" aria-label="Permalink to &quot;1. 通过 CC Switch 启用 CCWSPro&quot;">​</a></h3><p>打开 CC Switch，确认当前启用的是 <code>CCWS-PRO</code> Provider。如果你还没有添加 Provider，先按 <a href="/guide/config-switch">CC Switch 使用教程</a> 完成配置。</p><p>需要重点确认：</p><ul><li>Provider 名称为 <code>CCWS-PRO</code> 或其他你能识别的名称。</li><li>API 请求地址填写 <code>https://www.ccws.pro/v1</code>。</li><li>API Key 已复制完整。</li><li>启用 Provider 后，重新启动 Codex 客户端。</li></ul><h3 id="_2-打开项目文件夹" tabindex="-1">2. 打开项目文件夹 <a class="header-anchor" href="#_2-打开项目文件夹" aria-label="Permalink to &quot;2. 打开项目文件夹&quot;">​</a></h3><p>在 Codex 客户端中打开你要处理的项目文件夹。如果页面提供运行位置选择，优先选择 <code>Local</code>，让 Codex 在你的电脑本地项目中工作。</p><p><img src="'+s+'" alt="Codex 客户端选择项目文件夹" loading="lazy"></p><h3 id="_3-发起第一次测试" tabindex="-1">3. 发起第一次测试 <a class="header-anchor" href="#_3-发起第一次测试" aria-label="Permalink to &quot;3. 发起第一次测试&quot;">​</a></h3><p>打开项目后，先发送一个简单任务确认配置是否生效：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请用一句话介绍这个项目的主要功能，不要修改文件。</span></span></code></pre></div><p>如果 Codex 能正常回复，说明客户端已经可以通过当前 Provider 发起请求。</p><p><img src="'+d+`" alt="Codex 客户端首次测试对话" loading="lazy"></p><h2 id="命令行配置-进阶" tabindex="-1">命令行配置（进阶） <a class="header-anchor" href="#命令行配置-进阶" aria-label="Permalink to &quot;命令行配置（进阶）&quot;">​</a></h2><p>命令行方式也推荐使用 CC Switch 管理 Provider。你只需要在 CC Switch 中启用 <code>CCWS-PRO</code>，然后重新打开终端运行 Codex。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 你的项目目录</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex</span></span></code></pre></div><h2 id="手动配置方式" tabindex="-1">手动配置方式 <a class="header-anchor" href="#手动配置方式" aria-label="Permalink to &quot;手动配置方式&quot;">​</a></h2><p>如果你暂时不使用 CC Switch，也可以手动配置 Codex。请优先使用用户级配置文件，不要把 API Key 写进项目仓库。</p><p>配置文件位置：</p><table tabindex="0"><thead><tr><th>系统</th><th>配置文件</th></tr></thead><tbody><tr><td>macOS / Linux</td><td><code>~/.codex/config.toml</code></td></tr><tr><td>Windows</td><td><code>C:\\Users\\你的用户名\\.codex\\config.toml</code></td></tr></tbody></table><p>参考配置如下：</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">model_provider = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ccwspro&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">model = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;gpt-5.5&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">model_reasoning_effort = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;xhigh&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">model_providers</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ccwspro</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">name = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;CCWSPro&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">wire_api = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;responses&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">requires_openai_auth = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">base_url = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://www.ccws.pro/v1&quot;</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">注意</p><p>Codex 的 <code>base_url</code> 需要带 <code>/v1</code>，请填写 <code>https://www.ccws.pro/v1</code>。</p></div><p>然后在同一个 <code>.codex</code> 目录中创建或修改 <code>auth.json</code>：</p><table tabindex="0"><thead><tr><th>系统</th><th>API Key 文件</th></tr></thead><tbody><tr><td>macOS / Linux</td><td><code>~/.codex/auth.json</code></td></tr><tr><td>Windows</td><td><code>C:\\Users\\你的用户名\\.codex\\auth.json</code></td></tr></tbody></table><p>参考配置如下：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;OPENAI_API_KEY&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;你在CCWSPro申请的API key&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">安全提醒</p><p><code>auth.json</code> 里保存的是你的 API Key，不要把它放进项目目录，也不要提交到 Git 仓库。</p></div><p>保存 <code>config.toml</code> 和 <code>auth.json</code> 后，重新打开终端，再进入项目目录运行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 你的项目目录</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex</span></span></code></pre></div><h2 id="后续使用建议" tabindex="-1">后续使用建议 <a class="header-anchor" href="#后续使用建议" aria-label="Permalink to &quot;后续使用建议&quot;">​</a></h2><ul><li>普通需求直接在 Codex 里描述任务。</li><li>需要修改代码时，先让 Codex 说明计划，再确认执行。</li><li>切换 Provider 后，建议重启 Codex 再验证。</li><li>如果需要在 Codex 里生成或编辑图片，可继续配置 <a href="/guide/codex-image">Codex 生图教程</a>。</li><li>如果切换 Provider 后找不到原来的会话，可参考 <a href="/guide/config-switch#切换-provider-后显示-codex-会话历史">切换 Provider 后显示 Codex 会话历史</a>。</li></ul><h2 id="验证与排查" tabindex="-1">验证与排查 <a class="header-anchor" href="#验证与排查" aria-label="Permalink to &quot;验证与排查&quot;">​</a></h2><p>如果 Codex 无法正常请求，优先检查：</p><ul><li>CC Switch 当前启用的 Provider 是否为 <code>CCWS-PRO</code>。</li><li>Codex 请求地址是否为 <code>https://www.ccws.pro/v1</code>。</li><li>手动配置时，<code>auth.json</code> 是否放在正确的 <code>.codex</code> 目录中。</li><li>API Key 是否复制完整、是否仍然有效。</li><li>模型名称是否在 CCWSPro 当前支持范围内。</li><li>修改配置后是否重新打开终端或重启客户端。</li></ul><p>如果命令行提示 <code>codex: command not found</code>，说明 Codex CLI 还没有安装好，请回到 <a href="/guide/codex-install">Codex 下载安装</a> 重新验证。</p><p>如果客户端可以打开但请求失败，先回到 CC Switch 中重新启用一次 Provider，再重启 Codex 客户端验证。</p>`,42)])])}const x=a(l,[["render",n]]);export{g as __pageData,x as default};
